const calcData = $('Code').item.json;
const groqResponse = $input.first().json;
const aiAdvice = groqResponse.choices[0].message.content;

// FIXED: Now detailedScenarios is correctly passed from math engine to python
return [{
  json: {
    status: "success",
    escalation: false,
    student: calcData.studentName,
    semesterGpa: calcData.semesterGpa,
    cgpa: calcData.cgpa,
    detailedScenarios: calcData.detailedScenarios, // <--- YEH LINE LAZMI HONI CHAHIYE
    standing: calcData.standing,
    courses: calcData.courseResults,
    failedCourses: calcData.failedCourses,
    aiAdvice: aiAdvice,
    message: "Analysis complete. No escalation needed."
  }
}];

const rawData = $input.first().json;
const body = rawData.body || rawData;

const studentName    = body.name || "Student";
const pastCgpa       = parseFloat(body.pastCgpa) || 0;
const pastCredits    = parseFloat(body.pastCredits) || 0;
const pastCourses    = body.pastCourses || [];
const currentCourses = body.currentCourses || [];

if (currentCourses.length === 0 && pastCourses.length === 0) {
  return [{ json: { error: "No data provided." } }];
}

function getGradeFromMarks(marks) {
  if (marks >= 85) return { grade: "A",  points: 4.0  };
  if (marks >= 80) return { grade: "A-", points: 3.7  };
  if (marks >= 75) return { grade: "B+", points: 3.33 };
  if (marks >= 71) return { grade: "B",  points: 3.0  };
  if (marks >= 68) return { grade: "B-", points: 2.7  };
  if (marks >= 64) return { grade: "C+", points: 2.33 };
  if (marks >= 60) return { grade: "C",  points: 2.0  };
  if (marks >= 57) return { grade: "C-", points: 1.7  };
  if (marks >= 53) return { grade: "D+", points: 1.33 };
  if (marks >= 50) return { grade: "D",  points: 1.0  };
  return { grade: "F", points: 0.0 };
}

const gradeHierarchy = [
  { grade: "D",  points: 1.0  }, { grade: "D+", points: 1.33 },
  { grade: "C-", points: 1.7  }, { grade: "C",  points: 2.0  },
  { grade: "C+", points: 2.33 }, { grade: "B-", points: 2.7  },
  { grade: "B",  points: 3.0  }, { grade: "B+", points: 3.33 },
  { grade: "A-", points: 3.7  }, { grade: "A",  points: 4.0  }
];

const WEAK_GRADES = ["F","D-","D","D+","C-","C","C+"];

let semWtdPts = 0, semCredits = 0;
let failedCourses = [], courseResults = [], improvable = [];

for (const c of pastCourses) {
  const { grade, points } = getGradeFromMarks(parseFloat(c.marks));
  const cr = parseFloat(c.credits);
  if (WEAK_GRADES.includes(grade)) {
    improvable.push({ name: c.name + " (Past)", credits: cr, currentGrade: grade, currentPoints: points });
  }
}

for (const c of currentCourses) {
  const marks = parseFloat(c.marks);
  const cr    = parseFloat(c.credits);
  const { grade, points } = getGradeFromMarks(marks);
  semWtdPts  += points * cr;
  semCredits += cr;
  if (grade === "F") failedCourses.push(c.name);
  if (WEAK_GRADES.includes(grade)) {
    improvable.push({ name: c.name + " (Current)", credits: cr, currentGrade: grade, currentPoints: points });
  }
  courseResults.push({ name: c.name, credits: cr, grade, points });
}

const semGpa         = semCredits > 0 ? semWtdPts / semCredits : 0;
const oldPts         = pastCgpa * pastCredits;
const basePts        = oldPts + semWtdPts;
const totalCr        = pastCredits + semCredits;
const cgpa           = totalCr > 0 ? basePts / totalCr : (pastCgpa || 0);

let scenarios = "";
if (improvable.length > 0) {
  let totalMaxExtra = 0;
  for (const c of improvable) {
    scenarios += "If you improve " + c.name + " (" + c.currentGrade + "):\n";
    let maxExtra = 0;
    for (const g of gradeHierarchy) {
      if (g.points > c.currentPoints) {
        const extra   = (g.points - c.currentPoints) * c.credits;
        const newCgpa = ((basePts + extra) / totalCr).toFixed(2);
        scenarios    += "  " + g.grade + " -> CGPA: " + newCgpa + "\n";
        maxExtra      = extra;
      }
    }
    scenarios   += "\n";
    totalMaxExtra += maxExtra;
  }
  const maxPot = ((basePts + totalMaxExtra) / totalCr).toFixed(2);
  scenarios += "MAX POTENTIAL (all improved to A): CGPA " + maxPot;
} else {
  scenarios = "No weak grades found. Excellent standing!";
}

let standing = "", needsEscalation = false;
if      (cgpa >= 3.5) standing = "DISTINCTION";
else if (cgpa >= 3.0) standing = "GOOD STANDING";
else if (cgpa >= 2.0) standing = "SATISFACTORY";
else { standing = "PROBATION"; needsEscalation = true; }
if (failedCourses.length > 0) needsEscalation = true;

const escalationReason = needsEscalation
  ? "CGPA " + cgpa.toFixed(2) + " (" + standing + ")" + (failedCourses.length > 0 ? " | Failed: " + failedCourses.join(", ") : "")
  : "";

return [{
  json: {
    studentName,
    cgpa:             cgpa.toFixed(2),
    semesterGpa:      semGpa.toFixed(2),
    standing,
    courseResults,
    failedCourses,
    detailedScenarios: scenarios,
    needsEscalation,
    escalationReason
  }
}];
